# scripts/check_model_config_parity.py
# Compares staging and prod model configs.
# Fails if any inference-affecting field differs between environments.

import yaml, sys, json
from deepdiff import DeepDiff   # pip install deepdiff

STAGING_CONFIG = "config/model-config.staging.yaml"
PROD_CONFIG = "config/model-config.prod.yaml"

# Fields that MUST be identical across environments
INFERENCE_FIELDS = {
    "model", "temperature", "max_tokens", "top_p",
    "response_format", "prompt_version", "timeout_seconds",
}

# Fields allowed to differ (infrastructure concerns)
INFRA_FIELDS = {
    "rate_limit_per_minute", "replica_count", "log_level",
}

def load_model_configs(path: str) -> dict:
    with open(path) as f:
        raw = yaml.safe_load(f)
    return raw.get("model_configs", {})

def check_parity(staging: dict, prod: dict) -> list[str]:
    violations = []
    all_features = set(staging) | set(prod)

    for feature in all_features:
        if feature not in staging:
            violations.append(f"'{feature}' missing from staging config")
            continue
        if feature not in prod:
            violations.append(f"'{feature}' missing from prod config")
            continue

        s_cfg = staging[feature]
        p_cfg = prod[feature]

        for field in INFERENCE_FIELDS:
            s_val = s_cfg.get(field)
            p_val = p_cfg.get(field)
            if s_val != p_val:
                violations.append(
                    f"{feature}.{field}: staging={s_val!r}, prod={p_val!r}"
                )

    return violations

if __name__ == "__main__":
    staging = load_model_configs(STAGING_CONFIG)
    prod = load_model_configs(PROD_CONFIG)
    violations = check_parity(staging, prod)

    if violations:
        print("MODEL CONFIG PARITY VIOLATIONS:")
        for v in violations:
            print(f"  FAIL: {v}")
        print("\nStaging and prod must use identical model IDs, temperatures, and generation params.")
        sys.exit(1)

    print(f"Parity check passed: {len(staging)} feature(s) verified.")

# app/model_config.py
import os, yaml, pathlib
from dataclasses import dataclass
from functools import lru_cache

ENV = os.environ.get("APP_ENV", "dev")   # set by K8s configmap
CONFIG_DIR = pathlib.Path("config")

@dataclass(frozen=True)
class FeatureModelConfig:
    model: str
    temperature: float
    max_tokens: int
    top_p: float
    response_format: str
    prompt_version: str
    timeout_seconds: int

@dataclass(frozen=True)
class ModelConfig:
    env: str
    features: dict[str, FeatureModelConfig]

    def get(self, feature: str) -> FeatureModelConfig:
        if feature not in self.features:
            raise KeyError(f"No model config for feature '{feature}' in env '{self.env}'")
        return self.features[feature]

@lru_cache(maxsize=1)
def load_model_config() -> ModelConfig:
    config_path = CONFIG_DIR / f"model-config.{ENV}.yaml"
    if not config_path.exists():
        raise FileNotFoundError(f"Model config not found: {config_path}")

    with open(config_path) as f:
        raw = yaml.safe_load(f)

    features = {
        name: FeatureModelConfig(**{k: v for k, v in cfg.items()
                                   if k in FeatureModelConfig.__dataclass_fields__})
        for name, cfg in raw["model_configs"].items()
    }
    return ModelConfig(env=ENV, features=features)

# Usage
def answer_question(question: str, context: str) -> dict:
    config = load_model_config().get("rag_answer")
    from app.prompts import load_prompt
    import openai

    prompt = load_prompt("rag-answer", config.prompt_version)
    client = openai.OpenAI()
    response = client.chat.completions.create(
        model=config.model,
        temperature=config.temperature,
        max_tokens=config.max_tokens,
        top_p=config.top_p,
        messages=[
            {"role": "system", "content": prompt.system},
            {"role": "user", "content": prompt.render_user(
                question=question, context=context)},
        ],
        response_format={"type": config.response_format},
        timeout=config.timeout_seconds,
    )
    return {
        "answer": response.choices[0].message.content,
        "model": config.model,
        "prompt_sha": prompt.sha256[:12],
    }

