from fastapi import APIRouter
from app.model_config import load_model_config
from app.prompts import load_prompt
import hashlib, yaml, pathlib

router = APIRouter()

@router.get("/config")
def get_active_config():
    """Returns the active model configuration for all features.
    Used by: monitoring, post-incident debugging, parity checks.
    """
    config = load_model_config()
    result = {"env": config.env, "features": {}}

    for name, cfg in config.features.items():
        prompt = load_prompt(name.replace("_", "-"), cfg.prompt_version)
        result["features"][name] = {
            "model": cfg.model,
            "temperature": cfg.temperature,
            "max_tokens": cfg.max_tokens,
            "prompt_version": cfg.prompt_version,
            "prompt_sha": prompt.sha256[:16],
        }

    return result

